package main

import (
	"fmt"
	"net/http"
	"strings"
)

type User struct {
	ID    string
	Roles []string
}

func isAdmin(user *User) bool {
	for _, role := range user.Roles {
		if role == "admin" {
			return true
		}
	}
	return false
}

func handleChat(w http.ResponseWriter, r *http.Request) {
	userID := r.Header.Get("X-UserID")
	roles := strings.Split(r.Header.Get("X-Roles"), ",")

	user := &User{
		ID:    userID,
		Roles: roles,
	}

	if !isAdmin(user) {
		http.Error(w, "Unauthorized", http.StatusUnauthorized)
		return
	}

	message := r.FormValue("message")
	parts := strings.Split(message, " ")
	command := parts[0]

	switch command {
	case "/kick":
		if len(parts) < 2 {
			http.Error(w, "Invalid command", http.StatusBadRequest)
			return
		}
		targetID := parts[1]
		kickUser(targetID)
	case "/ban":
		if len(parts) < 2 {
			http.Error(w, "Invalid command", http.StatusBadRequest)
			return
		}
		targetID := parts[1]
		banUser(targetID)
	case "/giveitems":
		if len(parts) < 3 {
			http.Error(w, "Invalid command", http.StatusBadRequest)
			return
		}
		targetID := parts[1]
		items := strings.Join(parts[2:], " ")
		giveItems(targetID, items)
	default:
		fmt.Fprintf(w, "Message received: %s", message)
	}
}

func kickUser(userID string) {
	fmt.Printf("Kicking user: %s\n", userID)
}

func banUser(userID string) {
	fmt.Printf("Banning user: %s\n", userID)
}

func giveItems(userID, items string) {
	fmt.Printf("Giving items to user %s: %s\n", userID, items)
}

func main() {
	http.HandleFunc("/chat", handleChat)
	fmt.Println("Starting server on :8080")
	http.ListenAndServe(":8080", nil)
}